12	#define NGX_JS_FORM_URLENCODED  1
13	#define NGX_JS_FORM_MULTIPART   2
14	
15	/*
16	 * RFC 2046, section 5.1.1 limits boundary to 70 characters; we allow up
17	 * to 200 to tolerate non-conforming clients while bounding allocation.
18	 */
19	#define NGX_JS_FORM_MAX_BOUNDARY_LEN     200
20	#define NGX_JS_FORM_MAX_PART_HEADERS     32
21	#define NGX_JS_FORM_MAX_PART_HEADER_LINE 4096
22	#define NGX_JS_FORM_MAX_PART_HEADER_SIZE 16384
