31	static ngx_int_t ngx_js_form_parse_content_type(ngx_pool_t *pool,
32	    ngx_str_t *content_type, ngx_js_form_content_type_t *ct,
33	    ngx_str_t *error);
34	static ngx_int_t ngx_js_form_parse_urlencoded(ngx_pool_t *pool, u_char *body,
35	    size_t len, ngx_uint_t max_keys, ngx_js_form_t *form, ngx_str_t *error);
36	static ngx_int_t ngx_js_form_parse_multipart(ngx_pool_t *pool, u_char *body,
