64	
65	ngx_int_t
66	ngx_js_parse_form(ngx_pool_t *pool, ngx_str_t *content_type, u_char *body,
67	    size_t len, ngx_uint_t max_keys, ngx_js_form_t **form,
68	    ngx_str_t *error)
69	{
70	    ngx_int_t                    rc;
71	    ngx_js_form_t               *f;
72	    ngx_js_form_content_type_t   ct;
73	
74	    rc = ngx_js_form_parse_content_type(pool, content_type, &ct, error);
75	    if (rc != NGX_JS_FORM_OK) {
76	        return rc;
77	    }
78	
79	    f = ngx_pcalloc(pool, sizeof(ngx_js_form_t));
80	    if (f == NULL) {
81	        return NGX_ERROR;
82	    }
83	
84	    if (ngx_array_init(&f->entries, pool, 4, sizeof(ngx_js_form_entry_t))
85	        != NGX_OK)
86	    {
87	        return NGX_ERROR;
88	    }
89	
90	    switch (ct.type) {
91	    case NGX_JS_FORM_URLENCODED:
92	        rc = ngx_js_form_parse_urlencoded(pool, body, len, max_keys, f, error);
93	        break;
94	
95	    case NGX_JS_FORM_MULTIPART:
96	        rc = ngx_js_form_parse_multipart(pool, body, len, &ct.boundary,
97	                                         max_keys, f, error);
98	        break;
99	
100	    default:
101	        ngx_js_form_error(error, "unsupported content type");
102	        return NGX_JS_FORM_TYPE_ERROR;
103	    }
104	
105	    if (rc != NGX_JS_FORM_OK) {
106	        return rc;
107	    }
108	
109	    *form = f;
110	
111	    return NGX_JS_FORM_OK;
112	}
113	
114	
115	static ngx_int_t
116	ngx_js_form_parse_content_type(ngx_pool_t *pool, ngx_str_t *content_type,
117	    ngx_js_form_content_type_t *ct, ngx_str_t *error)
118	{
119	    u_char      *p, *end, *last, *value_start;
120	    ngx_int_t    rc;
121	    ngx_str_t    param, value;
122	    ngx_flag_t   quoted;
123	
124	    if (content_type == NULL || content_type->len == 0) {
125	        ngx_js_form_error(error, "request content type is required");
126	        return NGX_JS_FORM_TYPE_ERROR;
127	    }
128	
129	    ct->type = 0;
130	    ct->boundary.len = 0;
131	    ct->boundary.data = NULL;
132	
133	    p = content_type->data;
134	    end = p + content_type->len;
135	
136	    last = p;
137	
138	    while (last < end && *last != ';') {
139	        last++;
140	    }
141	
142	    value_start = ngx_js_form_skip_ows(p, last);
143	    p = last;
144	
145	    while (last > value_start && ngx_js_form_is_ows(last[-1])) {
146	        last--;
147	    }
148	
149	    if ((size_t) (last - value_start)
150	        == sizeof("application/x-www-form-urlencoded") - 1
151	        && ngx_strncasecmp(value_start,
152	                           (u_char *) "application/x-www-form-urlencoded",
153	                           last - value_start)
154	           == 0)
155	    {
156	        ct->type = NGX_JS_FORM_URLENCODED;
157	    }
158	
159	    if ((size_t) (last - value_start) == sizeof("multipart/form-data") - 1
160	        && ngx_strncasecmp(value_start, (u_char *) "multipart/form-data",
161	                           last - value_start)
162	           == 0)
163	    {
164	        ct->type = NGX_JS_FORM_MULTIPART;
165	    }
166	
167	    if (ct->type == 0) {
168	        ngx_js_form_error(error, "unsupported content type");
169	        return NGX_JS_FORM_TYPE_ERROR;
170	    }
171	
172	    while (p < end) {
173	        if (*p++ != ';') {
174	            ngx_js_form_error(error, "malformed content type");
175	            return NGX_JS_FORM_PARSE_ERROR;
176	        }
177	
178	        p = ngx_js_form_skip_ows(p, end);
179	
180	        rc = ngx_js_form_parse_param(pool, &p, end, &param, &value, &quoted,
181	                                     error);
182	        if (rc != NGX_JS_FORM_OK) {
183	            return rc;
184	        }
185	
186	        if (param.len == sizeof("boundary") - 1
187	            && ngx_strncasecmp(param.data, (u_char *) "boundary", param.len)
188	               == 0)
189	        {
190	            if (ct->boundary.data != NULL) {
191	                ngx_js_form_error(error, "duplicate boundary parameter");
192	                return NGX_JS_FORM_PARSE_ERROR;
193	            }
194	
195	            if (value.len == 0 || value.len > NGX_JS_FORM_MAX_BOUNDARY_LEN) {
196	                ngx_js_form_error(error, "invalid multipart boundary");
197	                return NGX_JS_FORM_PARSE_ERROR;
198	            }
199	
200	            ct->boundary = value;
201	        }
202	
203	        p = ngx_js_form_skip_ows(p, end);
204	
205	        if (p == end) {
206	            break;
207	        }
208	    }
209	
210	    if (ct->type == NGX_JS_FORM_MULTIPART && ct->boundary.data == NULL) {
211	        ngx_js_form_error(error, "multipart boundary is required");
212	        return NGX_JS_FORM_TYPE_ERROR;
213	    }
214	
215	    return NGX_JS_FORM_OK;
216	}
217	
218	
219	static ngx_int_t
220	ngx_js_form_parse_urlencoded(ngx_pool_t *pool, u_char *body, size_t len,
221	    ngx_uint_t max_keys, ngx_js_form_t *form, ngx_str_t *error)
222	{
223	    u_char      *p, *end, *amp, *eq;
224	    ngx_int_t    rc;
225	    ngx_str_t    name, value;
226	    ngx_uint_t   count;
227	
228	    count = 0;
229	    p = body;
230	    end = body + len;
231	
232	    if (len == 0) {
233	        return NGX_JS_FORM_OK;
234	    }
235	
236	    while (p < end) {
237	        if (*p == '&') {
238	            p++;
239	            continue;
240	        }
241	
242	        amp = p;
243	
244	        while (amp < end && *amp != '&') {
245	            amp++;
246	        }
247	
248	        eq = p;
249	
250	        while (eq < amp && *eq != '=') {
251	            eq++;
252	        }
253	
254	        rc = ngx_js_form_decode_urlencoded(pool, p, eq, &name, error);
255	        if (rc != NGX_JS_FORM_OK) {
256	            return rc;
257	        }
258	
259	        if (eq < amp) {
260	            eq++;
261	        }
262	
263	        rc = ngx_js_form_decode_urlencoded(pool, eq, amp, &value, error);
264	        if (rc != NGX_JS_FORM_OK) {
265	            return rc;
266	        }
267	
268	        rc = ngx_js_form_add_entry(form, pool, &name, &value, &count, max_keys,
269	                                   NULL, 0, error);
270	        if (rc != NGX_JS_FORM_OK) {
271	            return rc;
272	        }
273	
274	        if (amp == end) {
275	            break;
276	        }
277	
278	        p = amp + 1;
279	    }
280	
281	    return NGX_JS_FORM_OK;
282	}
283	
284	
285	static ngx_int_t
286	ngx_js_form_parse_multipart(ngx_pool_t *pool, u_char *body, size_t len,
287	    ngx_str_t *boundary, ngx_uint_t max_keys, ngx_js_form_t *form,
288	    ngx_str_t *error)
289	{
290	    size_t       dlen, cdlen;
291	    u_char      *p, *end, *marker, *next, *headers_end, *part_end, *scan;
292	    u_char      *delimiter;
293	    ngx_int_t    rc;
294	    ngx_str_t    name, value, filename;
295	    ngx_uint_t   count;
296	    ngx_flag_t   is_file;
297	
298	    count = 0;
299	    end = body + len;
300	    dlen = boundary->len + 2;
301	    cdlen = boundary->len + 4;
302	
303	    delimiter = ngx_pnalloc(pool, cdlen);
304	    if (delimiter == NULL) {
305	        return NGX_ERROR;
306	    }
307	
308	    delimiter[0] = '-';
309	    delimiter[1] = '-';
310	    ngx_memcpy(delimiter + 2, boundary->data, boundary->len);
311	    delimiter[dlen] = '-';
312	    delimiter[dlen + 1] = '-';
313	
314	    /*
315	     * Validate the body opening: a dash-boundary "--BOUNDARY" must
316	     * appear, and the close-delimiter "--BOUNDARY--" must not appear
317	     * before it.  The dash-boundary is a prefix of the close-delimiter,
318	     * so both searches use the same buffer with different lengths
319	     * (dlen = "--BOUNDARY", cdlen = "--BOUNDARY--").
320	     */
321	    p = ngx_js_form_find(body, end, delimiter, cdlen);
322	    marker = ngx_js_form_find(body, end, delimiter, dlen);
323	
324	    if (marker == NULL || (p != NULL && p < marker)) {
325	        ngx_js_form_error(error, "malformed multipart body");
326	        return NGX_JS_FORM_PARSE_ERROR;
327	    }
328	
329	    p = marker + dlen;
330	
331	    if (p + 2 <= end && p[0] == '-' && p[1] == '-') {
332	        return NGX_JS_FORM_OK;
333	    }
334	
335	    if (p + 2 > end || p[0] != '\r' || p[1] != '\n') {
336	        ngx_js_form_error(error, "malformed multipart boundary");
337	        return NGX_JS_FORM_PARSE_ERROR;
338	    }
339	
340	    p += 2;
341	
342	    for ( ;; ) {
343	        headers_end = ngx_js_form_find(p, end, (u_char *) "\r\n\r\n", 4);
344	        if (headers_end == NULL) {
345	            ngx_js_form_error(error, "missing multipart header separator");
346	            return NGX_JS_FORM_PARSE_ERROR;
347	        }
348	
349	        if ((size_t) (headers_end - p) > NGX_JS_FORM_MAX_PART_HEADER_SIZE) {
350	            ngx_js_form_error(error, "multipart headers are too large");
351	            return NGX_JS_FORM_PARSE_ERROR;
352	        }
353	
354	        rc = ngx_js_form_parse_part_headers(pool, p, headers_end, &name,
355	                                            &is_file, &filename, error);
356	        if (rc != NGX_JS_FORM_OK) {
357	            return rc;
358	        }
359	
360	        p = headers_end + sizeof("\r\n\r\n") - 1;
361	        scan = p;
362	
363	        for ( ;; ) {
364	            next = ngx_js_form_find(scan, end, (u_char *) "\r\n--", 4);
365	            if (next == NULL) {
366	                ngx_js_form_error(error, "truncated multipart body");
367	                return NGX_JS_FORM_PARSE_ERROR;
368	            }
369	
370	            if (next + (sizeof("\r\n--") - 1) + boundary->len <= end
371	                && ngx_memcmp(next + (sizeof("\r\n--") - 1), boundary->data,
372	                              boundary->len) == 0)
373	            {
374	                break;
375	            }
376	
377	            scan = next + sizeof("\r\n--") - 1;
378	        }
379	
380	        part_end = next;
381	
382	        if (is_file) {
383	            value.len = 0;
384	            value.data = (u_char *) "";
385	            form->has_files = 1;
386	
387	        } else {
388	            if (ngx_js_form_copy(pool, p, part_end, &value) != NGX_OK) {
389	                return NGX_ERROR;
390	            }
391	        }
392	
393	        rc = ngx_js_form_add_entry(form, pool, &name, &value, &count, max_keys,
394	                                   &filename, is_file, error);
395	        if (rc != NGX_JS_FORM_OK) {
396	            return rc;
397	        }
398	
399	        p = next + (sizeof("\r\n--") - 1) + boundary->len;
400	
401	        if (p + 2 <= end && p[0] == '-' && p[1] == '-') {
402	            return NGX_JS_FORM_OK;
403	        }
404	
405	        if (p + 2 > end || p[0] != '\r' || p[1] != '\n') {
406	            ngx_js_form_error(error, "malformed multipart boundary");
407	            return NGX_JS_FORM_PARSE_ERROR;
408	        }
409	
410	        p += 2;
411	    }
412	}
413	
414	
415	static ngx_int_t
416	ngx_js_form_parse_part_headers(ngx_pool_t *pool, u_char *start,
417	    u_char *end, ngx_str_t *name, ngx_flag_t *is_file, ngx_str_t *filename,
418	    ngx_str_t *error)
419	{
420	    u_char      *p, *line, *colon, *line_end;
421	    ngx_int_t    rc;
422	    ngx_str_t    key, value;
423	    ngx_uint_t   headers;
424	    ngx_flag_t   seen_disposition;
425	
426	    headers = 0;
427	    seen_disposition = 0;
428	
429	    name->len = 0;
430	    name->data = NULL;
431	    filename->len = 0;
432	    filename->data = (u_char *) "";
433	
434	    *is_file = 0;
435	
436	    for (p = start; p < end; p = line_end + 2) {
437	        line = p;
438	        line_end = ngx_js_form_find(p, end, (u_char *) "\r\n", 2);
439	        if (line_end == NULL) {
440	            line_end = end;
441	        }
442	
443	        if ((size_t) (line_end - line) > NGX_JS_FORM_MAX_PART_HEADER_LINE) {
444	            ngx_js_form_error(error, "multipart header line is too long");
445	            return NGX_JS_FORM_PARSE_ERROR;
446	        }
447	
448	        if (++headers > NGX_JS_FORM_MAX_PART_HEADERS) {
449	            ngx_js_form_error(error, "too many multipart headers");
450	            return NGX_JS_FORM_PARSE_ERROR;
451	        }
452	
453	        colon = line;
454	
455	        while (colon < line_end && *colon != ':') {
456	            colon++;
457	        }
458	
459	        if (colon == line_end) {
460	            ngx_js_form_error(error, "malformed multipart header");
461	            return NGX_JS_FORM_PARSE_ERROR;
462	        }
463	
464	        key.data = line;
465	        key.len = colon - line;
466	
467	        colon++;
468	        colon = ngx_js_form_skip_ows(colon, line_end);
469	
470	        value.data = colon;
471	        value.len = line_end - colon;
472	
473	        while (value.len > 0
474	               && ngx_js_form_is_ows(value.data[value.len - 1]))
475	        {
476	            value.len--;
477	        }
478	
479	        if (key.len == sizeof("Content-Disposition") - 1
480	            && ngx_strncasecmp(key.data, (u_char *) "Content-Disposition",
481	                               key.len)
482	               == 0)
483	        {
484	            if (seen_disposition) {
485	                ngx_js_form_error(error,
486	                                  "duplicate Content-Disposition header");
487	                return NGX_JS_FORM_PARSE_ERROR;
488	            }
489	
490	            rc = ngx_js_form_parse_disposition(pool, &value, name, is_file,
491	                                               filename, error);
492	            if (rc != NGX_JS_FORM_OK) {
493	                return rc;
494	            }
495	
496	            seen_disposition = 1;
497	        }
498	
499	        if (line_end == end) {
500	            break;
501	        }
502	    }
503	
504	    if (!seen_disposition) {
505	        ngx_js_form_error(error, "missing Content-Disposition header");
506	        return NGX_JS_FORM_PARSE_ERROR;
507	    }
508	
509	    return NGX_JS_FORM_OK;
510	}
511	
512	
513	static ngx_int_t
514	ngx_js_form_parse_disposition(ngx_pool_t *pool, ngx_str_t *value,
515	    ngx_str_t *name, ngx_flag_t *is_file, ngx_str_t *filename,
516	    ngx_str_t *error)
517	{
518	    u_char      *p, *end;
519	    ngx_int_t    rc;
520	    ngx_str_t    param, param_value;
521	    ngx_flag_t   quoted, seen_name, seen_file;
522	
523	    p = value->data;
524	    end = p + value->len;
525	
526	    while (p < end && *p != ';') {
527	        p++;
528	    }
529	
530	    if ((size_t) (p - value->data) != sizeof("form-data") - 1
531	        || ngx_strncasecmp(value->data, (u_char *) "form-data",
532	                           p - value->data)
533	           != 0)
534	    {
535	        ngx_js_form_error(error, "unsupported disposition type");
536	        return NGX_JS_FORM_PARSE_ERROR;
537	    }
538	
539	    seen_name = 0;
540	    seen_file = 0;
541	
542	    while (p < end) {
543	        if (*p++ != ';') {
544	            ngx_js_form_error(error, "malformed Content-Disposition");
545	            return NGX_JS_FORM_PARSE_ERROR;
546	        }
547	
548	        p = ngx_js_form_skip_ows(p, end);
549	
550	        rc = ngx_js_form_parse_param(pool, &p, end, &param, &param_value,
551	                                     &quoted, error);
552	        if (rc != NGX_JS_FORM_OK) {
553	            return rc;
554	        }
555	
556	        if (param.len == sizeof("name") - 1
557	            && ngx_strncasecmp(param.data, (u_char *) "name", param.len) == 0)
558	        {
559	            if (seen_name) {
560	                ngx_js_form_error(error, "duplicate name parameter");
561	                return NGX_JS_FORM_PARSE_ERROR;
562	            }
563	
564	            *name = param_value;
565	            seen_name = 1;
566	
567	        } else if (param.len == sizeof("filename") - 1
568	                   && ngx_strncasecmp(param.data, (u_char *) "filename",
569	                                      param.len)
570	                      == 0)
571	        {
572	            if (seen_file) {
573	                ngx_js_form_error(error, "duplicate filename parameter");
574	                return NGX_JS_FORM_PARSE_ERROR;
575	            }
576	
577	            *is_file = 1;
578	            *filename = param_value;
579	            seen_file = 1;
580	        }
581	
582	        p = ngx_js_form_skip_ows(p, end);
583	
584	        if (p == end) {
585	            break;
586	        }
587	    }
588	
589	    if (!seen_name) {
590	        ngx_js_form_error(error, "multipart field name is required");
591	        return NGX_JS_FORM_PARSE_ERROR;
592	    }
593	
594	    return NGX_JS_FORM_OK;
595	}
596	
597	
598	static ngx_int_t
599	ngx_js_form_parse_param(ngx_pool_t *pool, u_char **pp, u_char *end,
600	    ngx_str_t *param, ngx_str_t *value, ngx_flag_t *quoted, ngx_str_t *error)
601	{
602	    u_char  *p, *start;
603	
604	    p = ngx_js_form_skip_ows(*pp, end);
605	    start = p;
606	
607	    while (p < end && *p != '=' && *p != ';' && !ngx_js_form_is_ows(*p)) {
608	        p++;
609	    }
610	
611	    if (p == start) {
612	        ngx_js_form_error(error, "malformed parameter");
613	        return NGX_JS_FORM_PARSE_ERROR;
614	    }
615	
616	    if (ngx_js_form_copy(pool, start, p, param) != NGX_OK) {
617	        return NGX_ERROR;
618	    }
619	
620	    p = ngx_js_form_skip_ows(p, end);
621	
622	    if (p == end || *p != '=') {
623	        ngx_js_form_error(error, "malformed parameter");
624	        return NGX_JS_FORM_PARSE_ERROR;
625	    }
626	
627	    p++;
628	    p = ngx_js_form_skip_ows(p, end);
629	
630	    *quoted = 0;
631	
632	    if (p < end && *p == '"') {
633	        start = ++p;
634	
635	        while (p < end && *p != '"') {
636	            if (*p == '\\' && p + 1 < end) {
637	                p += 2;
638	                continue;
639	            }
640	
641	            p++;
642	        }
643	
644	        if (p == end) {
645	            ngx_js_form_error(error, "unterminated quoted parameter");
646	            return NGX_JS_FORM_PARSE_ERROR;
647	        }
648	
649	        if (ngx_js_form_copy_quoted(pool, start, p, value) != NGX_OK) {
650	            return NGX_ERROR;
651	        }
652	
653	        *quoted = 1;
654	        p++;
655	
656	    } else {
657	        start = p;
658	
659	        while (p < end && *p != ';' && !ngx_js_form_is_ows(*p)) {
660	            p++;
661	        }
662	
663	        if (start == p) {
664	            ngx_js_form_error(error, "empty parameter value");
665	            return NGX_JS_FORM_PARSE_ERROR;
666	        }
667	
668	        if (ngx_js_form_copy(pool, start, p, value) != NGX_OK) {
669	            return NGX_ERROR;
670	        }
671	    }
672	
673	    *pp = p;
674	
675	    return NGX_JS_FORM_OK;
676	}
677	
678	
679	static ngx_int_t
680	ngx_js_form_add_entry(ngx_js_form_t *form, ngx_pool_t *pool, ngx_str_t *name,
681	    ngx_str_t *value, ngx_uint_t *count, ngx_uint_t max_keys,
682	    ngx_str_t *filename, ngx_flag_t is_file, ngx_str_t *error)
683	{
684	    ngx_js_form_entry_t  *entry;
685	
686	    if (++(*count) > max_keys) {
687	        ngx_js_form_error(error, "maxKeys limit exceeded");
688	        return NGX_JS_FORM_PARSE_ERROR;
689	    }
690	
691	    entry = ngx_array_push(&form->entries);
692	    if (entry == NULL) {
693	        return NGX_ERROR;
694	    }
695	
696	    entry->name = *name;
697	    entry->value = *value;
698	    entry->is_file = is_file;
699	
700	    if (filename != NULL) {
701	        entry->filename = *filename;
702	
703	    } else {
704	        ngx_str_null(&entry->filename);
705	    }
706	
707	    return NGX_JS_FORM_OK;
708	}
709	
710	
711	static ngx_int_t
712	ngx_js_form_decode_urlencoded(ngx_pool_t *pool, u_char *start, u_char *end,
713	    ngx_str_t *dst, ngx_str_t *error)
714	{
715	    u_char     *p, *d, *out;
716	    ngx_int_t   n;
717	
718	    out = ngx_pnalloc(pool, (end - start) + 1);
719	    if (out == NULL) {
720	        return NGX_ERROR;
721	    }
722	
723	    d = out;
724	
725	    for (p = start; p < end; p++) {
726	        if (*p == '+') {
727	            *d++ = ' ';
728	            continue;
729	        }
730	
731	        if (*p == '%') {
732	            if (p + 2 >= end) {
733	                ngx_js_form_error(error, "malformed percent escape");
734	                return NGX_JS_FORM_PARSE_ERROR;
735	            }
736	
737	            n = ngx_hextoi(p + 1, 2);
738	            if (n == NGX_ERROR) {
739	                ngx_js_form_error(error, "malformed percent escape");
740	                return NGX_JS_FORM_PARSE_ERROR;
741	            }
742	
743	            *d++ = (u_char) n;
744	            p += 2;
745	            continue;
746	        }
747	
748	        *d++ = *p;
749	    }
750	
751	    *d = '\0';
752	    dst->data = out;
753	    dst->len = d - out;
754	
755	    return NGX_JS_FORM_OK;
756	}
757	
758	
759	static ngx_int_t
760	ngx_js_form_copy(ngx_pool_t *pool, u_char *start, u_char *end, ngx_str_t *dst)
761	{
762	    dst->len = end - start;
763	
764	    if (dst->len == 0) {
765	        dst->data = (u_char *) "";
766	        return NGX_OK;
767	    }
768	
769	    dst->data = ngx_pnalloc(pool, dst->len + 1);
770	    if (dst->data == NULL) {
771	        return NGX_ERROR;
772	    }
773	
774	    ngx_memcpy(dst->data, start, dst->len);
775	    dst->data[dst->len] = '\0';
776	
777	    return NGX_OK;
778	}
779	
780	
781	static ngx_int_t
782	ngx_js_form_copy_quoted(ngx_pool_t *pool, u_char *start, u_char *end,
783	    ngx_str_t *dst)
784	{
785	    u_char  *p, *d;
786	
787	    dst->len = end - start;
788	
789	    if (dst->len == 0) {
790	        dst->data = (u_char *) "";
791	        return NGX_OK;
792	    }
793	
794	    dst->data = ngx_pnalloc(pool, dst->len + 1);
795	    if (dst->data == NULL) {
796	        return NGX_ERROR;
797	    }
798	
799	    d = dst->data;
800	
801	    for (p = start; p < end; p++) {
802	        if (*p == '\\' && p + 1 < end) {
803	            p++;
804	        }
805	
806	        *d++ = *p;
807	    }
808	
809	    *d = '\0';
810	    dst->len = d - dst->data;
811	
812	    return NGX_OK;
813	}
814	
815	
816	static void
817	ngx_js_form_error(ngx_str_t *error, const char *text)
818	{
819	    error->data = (u_char *) text;
820	    error->len = ngx_strlen(text);
821	}
822	
823	
824	static u_char *
825	ngx_js_form_skip_ows(u_char *p, u_char *end)
826	{
827	    while (p < end && ngx_js_form_is_ows(*p)) {
828	        p++;
829	    }
830	
831	    return p;
832	}
833	
834	
835	static ngx_uint_t
836	ngx_js_form_is_ows(u_char ch)
837	{
838	    return ch == ' ' || ch == '\t';
839	}
840	
841	
842	static u_char *
843	ngx_js_form_find(u_char *start, u_char *end, u_char *pattern, size_t len)
844	{
845	    u_char  *p, *last;
846	
847	    if ((size_t) (end - start) < len) {
848	        return NULL;
849	    }
850	
851	    last = end - len + 1;
852	
853	    for (p = start; p < last; p++) {
854	        if (*p == pattern[0] && ngx_memcmp(p, pattern, len) == 0) {
855	            return p;
856	        }
857	    }
858	
859	    return NULL;
860	}
